package com.veetu.vadagai.notification;import com.veetu.vadagai.common.ApiResponse;import com.veetu.vadagai.user.CurrentUserService;import lombok.RequiredArgsConstructor;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/v1/notifications") @RequiredArgsConstructor public class NotificationController{private final NotificationRepository repo;private final CurrentUserService current;@GetMapping ApiResponse<List<Notification>> mine(){return ApiResponse.ok("Notifications",repo.findTop50ByRecipientIdAndDeletedFalseOrderByCreatedAtDesc(current.get().getId()));}}
